@startuml
title Class Diagram Title

interface IFoo {
  + void method()
}

class Bar {
  <<A>>
  + static String name
  - Foo foo
  # int x
  ~ int y
  - void method(String string)
}

class Foo {
  <<C>>
  + int x
  + void methodA()
}

class Qoo {
  <<C>>
  - Foo foo
}

Bar --|> IFoo : implements
Bar o-- Foo : Aggregation
Qoo *-- Foo : Composition
Foo --|> IFoo : extends

note right of Foo
  public : +
  protected : #
  default : ~
  private : -
  Foo는 Bar가 Aggregation한다.(Bar -o Foo)
  Foo는 Qoo가 Composition한다.(Qoo -* Foo)
  Foo는 IFoo를 상속한다.(Foo -|> IFoo)
end note

note bottom of Bar
  void method(String string){
    return string;
  }
end note

@enduml
